module top_module(
  input CLK, // clock signal
  input EN, // enable signal
  input TE, // test enable signal
  output ENCLK // gated clock signal
);reg unused_gated_clk;

  always @(*) begin
    if (TE) begin
      unused_gated_clk = 1;
    end else if (EN) begin
      unused_gated_clk = CLK;
    end else begin
      unused_gated_clk = 0;
    end
  end

  assign ENCLK = unused_gated_clk;

endmodule
